mapper.select:
SELECT i.id, i.title, i.price, i.status, i.wish_count, i.view_count, i.location, i.created_at, i.boosted_at, (SELECT ii.image_url FROM item_images ii WHERE ii.item_id = i.id AND ii.sort_order = 0 LIMIT 1) AS thumbnail_url, c.name AS category_name, u.id AS seller_id, u.nickname AS seller_nickname FROM items i JOIN users u ON i.seller_id = u.id JOIN categories c ON i.category_id = c.id WHERE i.deleted_at IS NULL AND i.hidden = false AND (i.status = 'SALE' OR i.status = #{status, jdbcType=VARCHAR})
AND i.status = #{status}
AND MATCH(i.title, i.description) AGAINST(#{keyword} IN BOOLEAN MODE)
AND (i.category_id = #{categoryId} OR i.category_id IN (SELECT id FROM categories WHERE parent_id = #{categoryId}))
AND i.price >= #{minPrice}
AND i.price <= #{maxPrice}
AND (i.trade_type = #{tradeType} OR i.trade_type = 'ALL')
AND i.item_condition = #{itemCondition}
AND i.seller_id = #{sellerId}
AND (i.created_at < #{cursorCreatedAt} OR (i.created_at = #{cursorCreatedAt} AND i.id < #{cursorId}))
ORDER BY
MATCH(i.title, i.description) AGAINST(#{keyword} IN BOOLEAN MODE) DESC,
COALESCE(i.boosted_at, i.created_at) DESC, i.id DESC LIMIT #{pageSize} + 1
